  componentDependencies: ["Button"],
  html: "<div class=\"reveal-container\">\n    <h2 id=\"player-title\">Jugador #1</h2>\n    \n    <div id=\"card-content\" class=\"card-container hidden\">\n        <div class=\"card-back\">?</div>\n    </div>\n\n    <p id=\"instruction\" class=\"instruction\">Asegúrate de que solo tú estés viendo la pantalla.</p>\n\n    <div class=\"actions\" id=\"actions-container\">\n    </div>\n</div>\n",
  css: ".reveal-container {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 2rem;\n    width: 100%;\n    max-width: 520px;\n    text-align: center;\n}\n\n.reveal-container h2 {\n    font-size: 1.6rem;\n    color: var(--primary-color);\n    margin: 0;\n    letter-spacing: 0.5px;\n}\n\n.card-container {\n    width: 100%;\n    height: 280px;\n    perspective: 1100px;\n    position: relative;\n    display: flex;\n    justify-content: center;\n    align-items: center;\n}\n\n.card-back {\n    width: 100%;\n    height: 100%;\n    background:\n        linear-gradient(135deg, rgba(var(--primary-color-rgb), 0.9), rgba(var(--secondary-color-rgb), 0.9)),\n        radial-gradient(circle at top left, rgba(255, 255, 255, 0.15), transparent 50%);\n    border-radius: calc(var(--border-radius-slice) * 3);\n    display: flex;\n    justify-content: center;\n    align-items: center;\n    font-size: 5rem;\n    color: rgba(255, 255, 255, 0.4);\n    font-weight: 800;\n    cursor: pointer;\n    box-shadow: 0 18px 30px rgba(0,0,0,0.25);\n    border: var(--slice-border) solid rgba(255, 255, 255, 0.2);\n    transition: transform 0.4s ease, box-shadow 0.4s ease;\n}\n\n.card-back:hover {\n    transform: translateY(-4px) scale(1.01);\n    box-shadow: 0 24px 45px rgba(0,0,0,0.3);\n}\n\n.role-card {\n    width: 100%;\n    height: 100%;\n    border-radius: calc(var(--border-radius-slice) * 3);\n    padding: 2rem;\n    display: flex;\n    flex-direction: column;\n    justify-content: center;\n    align-items: center;\n    gap: 1rem;\n    animation: flipIn 0.6s cubic-bezier(0.4, 0.0, 0.2, 1);\n    border: var(--slice-border) solid rgba(255, 255, 255, 0.25);\n}\n\n.imposter {\n    background: linear-gradient(135deg, #b31217, #e52d27);\n    color: white;\n}\n\n.crewmate {\n    background: linear-gradient(135deg, #11998e, #38ef7d);\n    color: white;\n}\n\n.secret-word {\n    font-size: 2.6rem;\n    font-weight: 800;\n    text-transform: uppercase;\n    word-break: break-word;\n    letter-spacing: 1px;\n    text-shadow: 0 6px 12px rgba(0,0,0,0.25);\n}\n\n.category-hint {\n    font-size: 0.9rem;\n    opacity: 0.9;\n    margin-top: 0.75rem;\n    background: rgba(0,0,0,0.2);\n    padding: 0.5rem 1.2rem;\n    border-radius: 2rem;\n}\n\n.instruction {\n    color: var(--font-secondary-color);\n    font-size: 0.9rem;\n    margin: 0;\n}\n\n@keyframes flipIn {\n    from {\n        transform: rotateY(90deg) scale(0.95);\n        opacity: 0;\n    }\n    to {\n        transform: rotateY(0) scale(1);\n        opacity: 1;\n    }\n}\n\n@media (max-width: 768px) {\n    .card-container {\n        height: 240px;\n    }\n\n    .secret-word {\n        font-size: 2.2rem;\n    }\n}\n\n@media (max-width: 480px) {\n    .card-container {\n        height: 220px;\n    }\n\n    .secret-word {\n        font-size: 1.9rem;\n    }\n}\n",
