  name: "GameFlow",
  category: "ImposterGameVisual",
  categoryType: "Visual",
  componentDependencies: ["Button"],
  html: "<div class=\"flow-container\">\n    <h2>¡Juego en Progreso!</h2>\n    <p class=\"flow-subtitle\">Completa las rondas de pistas y discutan antes de votar.</p>\n    \n    <div class=\"steps-guide\" id=\"steps-guide\">\n        <div class=\"step\">\n            <span class=\"step-number\">1</span>\n            <p><strong>Dar Pistas:</strong> Por turnos, cada jugador dice una palabra relacionada con la palabra secreta. ¡El impostor debe fingir!</p>\n        </div>\n        <div class=\"step\">\n            <span class=\"step-number\">2</span>\n            <p><strong>Discusión:</strong> Debatan quién dio la pista más sospechosa.</p>\n        </div>\n        <div class=\"step\">\n            <span class=\"step-number\">3</span>\n            <p><strong>Votación:</strong> A la cuenta de 3, señalen al sospechoso.</p>\n        </div>\n    </div>\n\n    <div class=\"actions\">\n        <div id=\"reveal-button-container\"></div>\n        <div id=\"new-game-button-container\"></div>\n    </div>\n\n    <div class=\"audio-controls\" id=\"audio-controls-game\"></div>\n\n    <div id=\"results-modal\" class=\"results-modal\" aria-hidden=\"true\">\n        <div class=\"results-card\">\n            <div class=\"results-header\">Resultado final</div>\n            <div class=\"results-grid\">\n                <div class=\"result-card\">\n                    <span class=\"result-label\">Impostores</span>\n                    <span class=\"result-value\" id=\"imposters-list\">-</span>\n                </div>\n                <div class=\"result-card\">\n                    <span class=\"result-label\">Palabra secreta</span>\n                    <span class=\"result-value\" id=\"secret-word\">-</span>\n                </div>\n                <div class=\"result-card\">\n                    <span class=\"result-label\">Categoria</span>\n                    <span class=\"result-value\" id=\"secret-category\">-</span>\n                </div>\n            </div>\n    <div class=\"modal-actions\">\n        <div id=\"close-modal-button-container\"></div>\n        <div id=\"keep-players-button-container\"></div>\n    </div>\n        </div>\n    </div>\n</div>\n",
  css: ".flow-container {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 2rem;\n    width: 100%;\n    max-width: 620px;\n}\n\n.flow-container h2 {\n    font-size: 1.8rem;\n    color: var(--primary-color);\n    margin: 0;\n    text-align: center;\n}\n\n.flow-subtitle {\n    margin: -0.4rem 0 0;\n    color: var(--font-secondary-color);\n    text-align: center;\n    font-size: 0.95rem;\n}\n\n.steps-guide {\n    display: flex;\n    flex-direction: column;\n    gap: 1.25rem;\n    width: 100%;\n    transition: opacity 0.3s ease, transform 0.3s ease;\n}\n\n.steps-guide.hidden {\n    opacity: 0;\n    transform: translateY(12px);\n    pointer-events: none;\n}\n\n.step {\n    display: grid;\n    grid-template-columns: auto 1fr;\n    align-items: flex-start;\n    gap: 1rem;\n    background: var(--primary-background-color);\n    padding: 1.2rem 1.3rem;\n    border-radius: calc(var(--border-radius-slice) * 2);\n    border: var(--slice-border) solid var(--primary-color-shade);\n    box-shadow: 0 10px 24px rgba(var(--primary-color-rgb), 0.08);\n    transition: transform 0.3s ease, border-color 0.3s ease;\n}\n\n.step:hover {\n    transform: translateY(-3px);\n    border-color: var(--primary-color);\n}\n\n.step-number {\n    background: var(--primary-color);\n    color: var(--primary-color-contrast);\n    width: 34px;\n    height: 34px;\n    display: flex;\n    justify-content: center;\n    align-items: center;\n    border-radius: 50%;\n    font-weight: 700;\n    flex-shrink: 0;\n    box-shadow: 0 6px 12px rgba(var(--primary-color-rgb), 0.35);\n}\n\n.step p {\n    margin: 0;\n    line-height: 1.6;\n    color: var(--font-primary-color);\n    font-size: 0.95rem;\n}\n\n.step strong {\n    color: var(--primary-color);\n    display: block;\n    margin-bottom: 0.3rem;\n}\n\n.actions {\n    display: flex;\n    justify-content: center;\n    gap: 1rem;\n    flex-wrap: wrap;\n}\n\n.actions slice-button {\n    min-width: 220px;\n}\n\n.results-modal {\n    position: fixed;\n    inset: 0;\n    background: rgba(0, 0, 0, 0.45);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    opacity: 0;\n    pointer-events: none;\n    transition: opacity 0.3s ease;\n    z-index: 2000;\n}\n\n.results-modal.open {\n    opacity: 1;\n    pointer-events: auto;\n}\n\n.results-card {\n    width: min(520px, 90vw);\n    background: var(--secondary-background-color);\n    border-radius: calc(var(--border-radius-slice) * 3);\n    border: var(--slice-border) solid var(--primary-color-shade);\n    padding: 2rem;\n    box-shadow: 0 24px 60px rgba(0, 0, 0, 0.25);\n    transform: translateY(20px) scale(0.98);\n    transition: transform 0.3s ease;\n}\n\n.results-modal.open .results-card {\n    transform: translateY(0) scale(1);\n}\n\n.results-header {\n    font-size: 1.1rem;\n    font-weight: 700;\n    color: var(--primary-color);\n    margin-bottom: 1rem;\n    text-align: center;\n}\n\n.results-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));\n    gap: 1rem;\n}\n\n.result-card {\n    background: var(--primary-background-color);\n    border-radius: calc(var(--border-radius-slice) * 2);\n    border: var(--slice-border) solid var(--primary-color-shade);\n    padding: 1rem;\n    display: flex;\n    flex-direction: column;\n    gap: 0.4rem;\n    align-items: center;\n    text-align: center;\n}\n\n.result-label {\n    font-size: 0.85rem;\n    color: var(--font-secondary-color);\n    text-transform: uppercase;\n    letter-spacing: 0.6px;\n}\n\n.result-value {\n    font-size: 1.1rem;\n    font-weight: 700;\n    color: var(--font-primary-color);\n}\n\n.modal-actions {\n    margin-top: 1.5rem;\n    display: flex;\n    justify-content: center;\n    gap: 0.8rem;\n    flex-wrap: wrap;\n}\n\n@media (max-width: 768px) {\n    .flow-container h2 {\n        font-size: 1.6rem;\n    }\n\n    .flow-subtitle {\n        font-size: 0.9rem;\n    }\n\n    .step {\n        padding: 1rem;\n    }\n}\n",
